import random
import sys

def jeu_devinette():
    nombre_secret = random.randint(1, 100)
    tentatives = 0

    print("Bienvenue dans le jeu de devinette !")
    print("J'ai choisi un nombre entre 1 et 100.")

    # Sandbox/pipe = pas de terminal interactif : on joue une demo auto
    # (bisection) qui se termine, au lieu de bloquer sur input() (EOFError).
    auto = not sys.stdin.isatty()
    bas, haut = 1, 100

    while True:
        if auto:
            proposition = (bas + haut) // 2
            print(f"Devine le nombre : {proposition}")
        else:
            try:
                proposition = int(input("Devine le nombre : "))
            except (EOFError, KeyboardInterrupt):
                print("\nPartie interrompue.")
                break
            except ValueError:
                print("Entrez un nombre valide.")
                continue

        tentatives += 1

        if proposition < nombre_secret:
            print("Trop petit !")
            bas = proposition + 1
        elif proposition > nombre_secret:
            print("Trop grand !")
            haut = proposition - 1
        else:
            print(f"Bravo ! Tu as trouve en {tentatives} tentatives.")
            break

if __name__ == "__main__":
    jeu_devinette()
